-- Suggestions come from people followed by people I follow, excluding unsafe or already-connected users.
CREATE VIEW ada_follow_suggestions AS SELECT DISTINCT suggested.handle FROM follows mine JOIN follows second_degree ON second_degree.follower_id = mine.followee_id JOIN users suggested ON suggested.id = second_degree.followee_id WHERE mine.follower_id = 1 AND suggested.id <> 1 AND NOT EXISTS (SELECT 1 FROM follows already WHERE already.follower_id=1 AND already.followee_id=suggested.id) AND NOT EXISTS (SELECT 1 FROM blocks b WHERE b.blocker_id=1 AND b.blocked_id=suggested.id) ORDER BY suggested.handle;
